import{_ as t,o as e,c as l,ag as r}from"./chunks/framework.CxZWPeXl.js";const g=JSON.parse('{"title":"階段管理","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/admin-stages.md","filePath":"zh-TW/admin-stages.md"}'),o={name:"zh-TW/admin-stages.md"};function i(n,a,s,h,d,u){return e(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="階段管理" tabindex="-1">階段管理 <a class="header-anchor" href="#階段管理" aria-label="Permalink to &quot;階段管理&quot;">​</a></h1><blockquote><p>定義對話練習的銷售階段，設定評量標準與目標。</p></blockquote><h2 id="概覽" tabindex="-1">概覽 <a class="header-anchor" href="#概覽" aria-label="Permalink to &quot;概覽&quot;">​</a></h2><p>銷售階段是模擬演練的基礎。每個階段代表對話中的一個關鍵步驟；AI 將根據這些設定來追蹤及評估使用者的表現。</p><blockquote><p>僅限管理員存取。</p></blockquote><h2 id="介面結構" tabindex="-1">介面結構 <a class="header-anchor" href="#介面結構" aria-label="Permalink to &quot;介面結構&quot;">​</a></h2><p>管理頁面會依序顯示階段列表（通常為第 1 至第 5 階段）：</p><ul><li><strong>卡片標題</strong>: 格式為「第 N 階段：{階段名稱}」（支援雙語顯示，例如越南文與繁體中文）。</li><li><strong>客戶狀態 (描述)</strong>: 客戶在該階段的預期心理狀態或行為表現。</li><li><strong>操作按鈕</strong>: 提供編輯（鉛筆圖示）與刪除（垃圾桶圖示）階段的功能。</li></ul><hr><h2 id="階段屬性" tabindex="-1">階段屬性 <a class="header-anchor" href="#階段屬性" aria-label="Permalink to &quot;階段屬性&quot;">​</a></h2><h3 id="階段編號" tabindex="-1">階段編號 <a class="header-anchor" href="#階段編號" aria-label="Permalink to &quot;階段編號&quot;">​</a></h3><ul><li>決定階段順序。必須為正整數且不可重複。建立後無法修改。</li></ul><h3 id="階段名稱" tabindex="-1">階段名稱 <a class="header-anchor" href="#階段名稱" aria-label="Permalink to &quot;階段名稱&quot;">​</a></h3><ul><li>銷售步驟的正式名稱（例如：1. 破冰、2. 需求探索、3. 促成）。支援雙語輸入。</li></ul><h3 id="當前客戶狀態" tabindex="-1">當前客戶狀態 <a class="header-anchor" href="#當前客戶狀態" aria-label="Permalink to &quot;當前客戶狀態&quot;">​</a></h3><ul><li>描述客戶的心理與狀態。AI 會將此作為基準，評估業務員是否成功突破該心理障礙並推進至下一階。</li></ul><hr><h2 id="操作指南" tabindex="-1">操作指南 <a class="header-anchor" href="#操作指南" aria-label="Permalink to &quot;操作指南&quot;">​</a></h2><ul><li><strong>新增階段</strong>: 點擊新增按鈕，輸入對應語言的編號、名稱與描述。</li><li><strong>編輯</strong>: 點擊卡片上的編輯圖示（註：無法修改階段編號）。</li><li><strong>刪除</strong>: 點擊刪除圖示。警告：刪除階段可能會影響過去練習紀錄的評量報告結果。</li></ul><hr><h2 id="設計建議" tabindex="-1">設計建議 <a class="header-anchor" href="#設計建議" aria-label="Permalink to &quot;設計建議&quot;">​</a></h2><ol><li><strong>合理的推進</strong>: 由淺入深，符合自然的銷售流程。</li><li><strong>明確的目標</strong>: 每個階段應具備具體且可衡量的目標，以便 AI 精準打分。</li><li><strong>寫實的描述</strong>: 客戶的心理狀態設定應貼近真實情況。</li><li><strong>數量適中</strong>: 每場單一練習的階段數建議介於 3 到 7 個之間。</li></ol>',22)])])}const b=t(o,[["render",i]]);export{g as __pageData,b as default};
